    q = n if n <= 6000 else 6000

    # Build lines of input
    lines = [f"{n} {q}"]
    for i in range(1, q + 1):
        # Full-range update
        l, r = 1, n
        # Alternate extreme values
        x = 1000000000 if (i & 1) else 0
        lines.append(f"{l} {r} {x}")

    return "\n".join(lines)
