import re as _re

def _add_alternate_keys(generators_dict: Dict[str, Callable]) -> Dict[str, Callable]:
    """Add 'problem/strategy_NN' style keys to the generators dict."""
    augmented = dict(generators_dict)
    for key, func in list(generators_dict.items()):
        # Match pattern: strategy_NN/problem_sNN_single_in_generator.py
        m = _re.match(r'strategy_(\d+)/(\w+)_s\d+_single_in_generator\.py$', key)
        if m:
            strategy_num = m.group(1)
            problem_name = m.group(2)
            alt_key = f"{problem_name}/strategy_{strategy_num}"
            if alt_key not in augmented:
                augmented[alt_key] = func
    return augmented


